## Set Up Lucia Auth v3 in Next.js

### 1. Install Dependencies

```bash
# Core Lucia + Prisma adapter + password hashing
npm install lucia @lucia-auth/adapter-prisma @node-rs/argon2
```

Alternative adapters:

```bash
# Drizzle adapter
npm install lucia @lucia-auth/adapter-drizzle

# SQLite / libsql adapter
npm install lucia @lucia-auth/adapter-sqlite
```

### 2. Add Lucia Tables to Prisma Schema

Add to `prisma/schema.prisma`:

```prisma
model User {
  id       String    @id @default(cuid())
  email    String    @unique
  password String
  sessions Session[]
}

model Session {
  id        String   @id
  userId    String
  expiresAt DateTime
  user      User     @relation(fields: [userId], references: [id], onDelete: Cascade)
}
```

```bash
npx prisma migrate dev --name add-lucia-tables
```

### 3. Create the Lucia Instance

Create `src/lib/auth.ts`:

```typescript
import { Lucia } from 'lucia';
import { PrismaAdapter } from '@lucia-auth/adapter-prisma';
import { prisma } from '@/lib/prisma';

const adapter = new PrismaAdapter(prisma.session, prisma.user);

export const lucia = new Lucia(adapter, {
  sessionCookie: {
    attributes: {
      secure: process.env.NODE_ENV === 'production',
    },
  },
  getUserAttributes: (attributes) => ({
    email: attributes.email,
  }),
});

declare module 'lucia' {
  interface Register {
    Lucia: typeof lucia;
    DatabaseUserAttributes: { email: string };
  }
}
```

### 4. Create the validateRequest Helper

Create `src/lib/validate-request.ts`:

```typescript
import { cookies } from 'next/headers';
import { cache } from 'react';
import { lucia } from '@/lib/auth';

export const validateRequest = cache(async () => {
  const sessionId = cookies().get(lucia.sessionCookieName)?.value ?? null;

  if (!sessionId) return { user: null, session: null };

  const { user, session } = await lucia.validateSession(sessionId);

  try {
    if (session?.fresh) {
      const cookie = lucia.createSessionCookie(session.id);
      cookies().set(cookie.name, cookie.value, cookie.attributes);
    }
    if (!session) {
      const cookie = lucia.createBlankSessionCookie();
      cookies().set(cookie.name, cookie.value, cookie.attributes);
    }
  } catch {
    // Next.js throws when setting cookies during static rendering — safe to ignore
  }

  return { user, session };
});
```

### 5. Create Sign-Up API Route

Create `src/app/api/auth/signup/route.ts`:

```typescript
import { NextRequest, NextResponse } from 'next/server';
import { cookies } from 'next/headers';
import { hash } from '@node-rs/argon2';
import { lucia } from '@/lib/auth';
import { prisma } from '@/lib/prisma';

export async function POST(req: NextRequest) {
  const { email, password } = await req.json();

  if (!email || !password || password.length < 8) {
    return NextResponse.json({ error: 'Invalid input' }, { status: 400 });
  }

  const passwordHash = await hash(password, {
    memoryCost: 19456,
    timeCost: 2,
    outputLen: 32,
    parallelism: 1,
  });

  const user = await prisma.user.create({
    data: { email, password: passwordHash },
  });

  const session = await lucia.createSession(user.id, {});
  const sessionCookie = lucia.createSessionCookie(session.id);
  cookies().set(sessionCookie.name, sessionCookie.value, sessionCookie.attributes);

  return NextResponse.json({ success: true });
}
```

### 6. Create Sign-In API Route

Create `src/app/api/auth/signin/route.ts`:

```typescript
import { NextRequest, NextResponse } from 'next/server';
import { cookies } from 'next/headers';
import { verify } from '@node-rs/argon2';
import { lucia } from '@/lib/auth';
import { prisma } from '@/lib/prisma';

export async function POST(req: NextRequest) {
  const { email, password } = await req.json();

  const user = await prisma.user.findUnique({ where: { email } });

  if (!user || !(await verify(user.password, password))) {
    return NextResponse.json({ error: 'Invalid credentials' }, { status: 401 });
  }

  const session = await lucia.createSession(user.id, {});
  const sessionCookie = lucia.createSessionCookie(session.id);
  cookies().set(sessionCookie.name, sessionCookie.value, sessionCookie.attributes);

  return NextResponse.json({ success: true });
}
```

### 7. Create Sign-Out API Route

Create `src/app/api/auth/signout/route.ts`:

```typescript
import { NextResponse } from 'next/server';
import { cookies } from 'next/headers';
import { lucia } from '@/lib/auth';
import { validateRequest } from '@/lib/validate-request';

export async function POST() {
  const { session } = await validateRequest();

  if (!session) {
    return NextResponse.json({ error: 'Not authenticated' }, { status: 401 });
  }

  await lucia.invalidateSession(session.id);

  const blank = lucia.createBlankSessionCookie();
  cookies().set(blank.name, blank.value, blank.attributes);

  return NextResponse.json({ success: true });
}
```

### 8. Protect Routes in Middleware

Create or update `src/middleware.ts`:

```typescript
import { NextRequest, NextResponse } from 'next/server';

export function middleware(request: NextRequest) {
  const sessionCookie = request.cookies.get('auth_session');
  const isAuthPage = request.nextUrl.pathname.startsWith('/auth');

  if (!sessionCookie && !isAuthPage) {
    return NextResponse.redirect(new URL('/auth/signin', request.url));
  }

  if (sessionCookie && isAuthPage) {
    return NextResponse.redirect(new URL('/dashboard', request.url));
  }
}

export const config = {
  matcher: ['/dashboard/:path*', '/auth/:path*'],
};
```

### 9. Use in Server Components

```typescript
import { validateRequest } from '@/lib/validate-request';
import { redirect } from 'next/navigation';

export default async function DashboardPage() {
  const { user } = await validateRequest();

  if (!user) redirect('/auth/signin');

  return <div>Welcome, {user.email}</div>;
}
```

## Common Errors

**`lucia.sessionCookieName is undefined`**
- You're on Lucia v2; upgrade: `npm install lucia@latest`
- v3 API differs significantly from v2 — do not mix docs

**`new PrismaAdapter()` receives wrong arguments**
- Pass the Prisma model delegates: `new PrismaAdapter(prisma.session, prisma.user)`
- Do not pass the whole `prisma` client

**Sessions expire immediately / not persisted**
- Ensure the `session.fresh` check runs and re-sets the cookie in `validateRequest`
- Default session lifetime is 30 days

**`cookies() cannot be called outside a request scope`**
- Wrap cookie writes in try/catch inside Server Components — Next.js throws during static rendering

**Password verification always fails**
- Use `@node-rs/argon2` consistently for both `hash()` and `verify()`
- Mixing bcrypt and argon2 will always return false

## What NOT to Do

- **Do NOT import from `'lucia/middleware'`** — that was Lucia v2; v3 has no such export
- **Do NOT skip the `declare module 'lucia'`** block — TypeScript types on `user` will be `never`
- **Do NOT call `validateRequest()` in Client Components** — it uses `cookies()` which is server-only
- **Do NOT use `lucia.getSession()` from v2 docs** — v3 uses `lucia.validateSession(sessionId)`
- **Do NOT store raw passwords** — always hash with argon2 before writing to the database
- **Do NOT rely on middleware alone for auth** — always call `validateRequest()` in Server Components too, as middleware only checks cookie existence, not session validity
